const now = new Date();

const start = new Date(now.getFullYear(), now.getMonth() - 1, 1);
const end = new Date(now.getFullYear(), now.getMonth(), 0);

function fmt(d) {
  return d.toISOString().slice(0, 10);
}

return [
  {
    json: {
      start: fmt(start),
      end: fmt(end)
    }
  }
];

let data = $json.data;

// Falls HTTP Node JSON als String liefert
if (typeof data === 'string') {
  try {
    const parsed = JSON.parse(data);
    data = parsed.data || parsed;
  } catch (e) {
    data = [];
  }
}

// Falls kompletter Firefly-Response direkt im Item liegt
if (!data && $json.attributes) {
  data = [$json];
}

// Falls data ein einzelnes Objekt ist
if (data && !Array.isArray(data)) {
  data = [data];
}

// Fallback
if (!Array.isArray(data)) {
  data = [];
}

const transactions = [];

for (const entry of data) {
  const splits = entry.attributes?.transactions || [];

  for (const t of splits) {
    transactions.push({
      date: t.date || '',
      description: t.description || '',
      amount: Math.abs(parseFloat(t.amount || 0)),
      category: t.category_name || 'Ohne Kategorie',
      budget: t.budget_name || '',
      source: t.source_name || '',
      destination: t.destination_name || '',
      type: t.type || ''
    });
  }
}

return [
  {
    json: {
      transaction_count: transactions.length,
      transactions,
      prompt: `
Analysiere diese Firefly-III-Transaktionen des aktuellen Monats.

Erkenne Fixkosten, regelmäßige Ausgaben und wahrscheinliche Abos.

Ignoriere:
- einmalige Einkäufe
- Lebensmittel
- Bargeldabhebungen
- interne Umbuchungen

Antworte NUR als gültiges JSON ohne Markdown.

Format:
{
  "fixkosten_gesamt": 0,
  "anzahl_fixkosten": 0,
  "fixkosten": [
    {
      "name": "",
      "betrag": 0,
      "kategorie": "",
      "sicherheit": "hoch|mittel|niedrig",
      "begruendung": ""
    }
  ],
  "vermutliche_abos": [],
  "auffaelligkeiten": [],
  "zusammenfassung": ""
}

Transaktionen:
${JSON.stringify(transactions, null, 2)}
`
    }
  }
];

let raw =
  $json.output ||
  $json.text ||
  $json.message ||
  $json.content ||
  $json.choices?.[0]?.message?.content ||
  $json;

let parsed;

if (typeof raw === 'object') {
  parsed = raw;
} else {
  raw = String(raw)
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  parsed = JSON.parse(raw);
}

// Falls OpenAI Node das Ergebnis in output als Array liefert
if (Array.isArray(parsed)) {
  parsed = parsed[0];
}

return [
  {
    json: parsed
  }
];

const transactions = $input.first().json.transactions || [];

// Echtes Firefly Konto 112
const accountRaw = $('Firefly Konto holen').first().json;
const accountAttr = accountRaw.data?.attributes || {};

const realAccountBalance = Number(
  accountAttr.current_balance ??
  accountAttr.virtual_balance ??
  0
);

const accountName = accountAttr.name || 'Volksbank';

let raw =
  $json.content?.[0]?.text ||
  $json.output_text ||
  $json.output ||
  $json.text ||
  $json;

let ai;

if (typeof raw === 'object') {
  ai = raw;
} else {
  raw = String(raw)
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  ai = JSON.parse(raw);
}

function escTag(v) {
  return String(v || 'Unbekannt')
    .replace(/ /g, '\\ ')
    .replace(/,/g, '\\,')
    .replace(/=/g, '\\=')
    .replace(/:/g, '\\:');
}

function num(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
}

const now = new Date();
const month = now.toISOString().slice(0, 7);
const ts = Date.now() * 1000000;

let income = 0;
let expenses = 0;
let transfer = 0;

let countIncome = 0;
let countExpenses = 0;

const byCategory = {};
const byMerchant = {};
const byDay = {};

for (const t of transactions) {
  const amount = num(t.amount);
  const type = String(t.type || '').toLowerCase();

  const category = t.category || 'Ohne Kategorie';
  const merchant = t.destination || t.source || t.description || 'Unbekannt';
  const day = String(t.date || '').slice(0, 10);

  if (type === 'deposit') {
    income += amount;
    countIncome++;
  }

  if (type === 'withdrawal') {
    expenses += amount;
    countExpenses++;

    byCategory[category] = (byCategory[category] || 0) + amount;
    byMerchant[merchant] = (byMerchant[merchant] || 0) + amount;
    byDay[day] = (byDay[day] || 0) + amount;
  }

  if (type === 'transfer') {
    transfer += amount;
  }
}

const monthBalance = income - expenses;

const fixkostenGesamt = num(ai.fixkosten_gesamt);
const fixkostenCount = num(ai.anzahl_fixkosten || (ai.fixkosten || []).length);
const fixkostenQuote = expenses > 0 ? (fixkostenGesamt / expenses) * 100 : 0;

const variableExpenses = Math.max(expenses - fixkostenGesamt, 0);

const lines = [];

// Echtes Konto
lines.push(
  `firefly_account,account=${escTag(accountName)},account_id=112 balance=${realAccountBalance} ${ts}`
);

// Monatsübersicht
lines.push(
  `firefly_month,month=${escTag(month)} income=${income},expenses=${expenses},month_balance=${monthBalance},account_balance=${realAccountBalance},fixkosten_gesamt=${fixkostenGesamt},fixkosten_quote=${fixkostenQuote},variable_expenses=${variableExpenses},count_income=${countIncome},count_expenses=${countExpenses} ${ts}`
);

// Kategorien
for (const [category, value] of Object.entries(byCategory)) {
  lines.push(
    `firefly_category,month=${escTag(month)},category=${escTag(category)} expenses=${value} ${ts}`
  );
}

// Top Händler
for (const [merchant, value] of Object.entries(byMerchant)) {
  lines.push(
    `firefly_merchant,month=${escTag(month)},merchant=${escTag(merchant)} expenses=${value} ${ts}`
  );
}

// Tagesausgaben
for (const [day, value] of Object.entries(byDay)) {
  const dayTs = new Date(day + 'T12:00:00').getTime() * 1000000;
  lines.push(
    `firefly_daily,month=${escTag(month)},day=${escTag(day)} expenses=${value} ${dayTs}`
  );
}

// KI-Fixkosten
lines.push(
  `firefly_fixkosten,type=summary,month=${escTag(month)} fixkosten_gesamt=${fixkostenGesamt},anzahl_fixkosten=${fixkostenCount} ${ts}`
);

for (const f of (ai.fixkosten || [])) {
  const name = escTag(f.name || f.empfaenger || f.beschreibung || 'Unbekannt');
  const betrag = num(f.betrag);

  lines.push(
    `firefly_fixkosten_detail,month=${escTag(month)},name=${name} betrag=${betrag} ${ts}`
  );
}

return [
  {
    json: {
      lineProtocol: lines.join('\n'),

      debug_account_balance: realAccountBalance,
      debug_month_balance: monthBalance,
      debug_income: income,
      debug_expenses: expenses,
      debug_fixkosten: fixkostenGesamt,
      debug_variable_expenses: variableExpenses,
      debug_lines: lines.length,

      summary: ai.zusammenfassung || ai.kurze_zusammenfassung || ''
    }
  }
];
